const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t;
let input = [];
readline.on('line', line => {
    if (i === 0) {
        t = parseInt(line);
    } else {
        input.push(line.split(' ').map(x => parseInt(x)));
    }
    i++;
    if (i === t * 2 + 1) {
        for (let j = 0; j < t; j++) {
            let n = input[j * 2][0];
            let arr = input[j * 2 + 1];
            arr.sort((a, b) => a - b);
            let median = arr[Math.floor(n / 2)];
            let sum = 0;
            for (let k = 0; k < n; k++) {
                sum += Math.abs(arr[k] - median);
            }
            console.log(sum);
        }
    }
});
